def bubble_sort(array):
    n = len(array)
    for i in range(n):
        swap = False
        for j in range(0, n-i-1):
            if array[j] > array[j+1]:
                array[j], array[j+1] = array[j+1], array[j]
                swap = True
        if not swap:
            break

array = [64, 34, 25, 12, 22, 11, 90]
bubble_sort(array)
print("Sorted array:", array)

