def linear_search(array, value):
    found = False
    counter = 0
    number_of_values = len(array)
    while not found and counter < number_of_values:
        if array[counter] == value:
            found = True
        else:
            counter += 1
    if found:
        print(f"{value} found at position {counter} in the list.")
    else:
        print(f"{value} not found.")

array = [10, 20, 30, 40, 50]
linear_search(array, 30)

